"use client";
import Link from "next/link";
import { useEffect, useState } from "react";
import { useRouter } from "next/navigation";
import VendorSidebar from "./sidebar";
import { Booking, getVendorBookings } from "../../../lib/bookings";
import { getMyServices, getVendorProfile } from "../../../lib/vendor-api";
import { me } from "../../../lib/auth";

export default function VendorDashboard() {
  const router = useRouter(); const [bookings, setBookings] = useState<Booking[]>([]); const [services, setServices] = useState(0); const [approval, setApproval] = useState<string | null>(null); const [error, setError] = useState(""); const [loading, setLoading] = useState(true);
  const load = () => Promise.all([me(), getVendorBookings(), getMyServices(), getVendorProfile()]).then(([session, bookingData, serviceData, profileData]) => { if (!session?.user || session.user.role !== "vendor") { router.replace("/vendor/auth"); return; } setBookings(bookingData.bookings); setServices(serviceData.services.length); setApproval(profileData.vendor?.approvalStatus || null); setError(""); }).catch((e) => setError(e.message || "Unable to load dashboard.")).finally(() => setLoading(false));
  useEffect(() => { load(); }, [router]);
  const pending = bookings.filter((b) => b.status === "pending").length; const accepted = bookings.filter((b) => b.status === "confirmed").length; const completed = bookings.filter((b) => b.status === "completed").length;
  return <div className="min-h-screen bg-[#fffdfc] md:flex"><VendorSidebar /><main className="flex-1 p-5 pt-20 md:p-10"><p className="text-sm font-bold uppercase tracking-[.16em] text-[#8B000F]">Vendor workspace</p><h1 className="mt-2 font-serif text-4xl font-bold text-[#5c1632]">Dashboard overview</h1>{loading ? <div className="mt-8 grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{Array.from({length:4}).map((_,i)=><div key={i} className="h-32 animate-pulse rounded-2xl bg-[#f7e9e4]" />)}</div> : error ? <div role="alert" className="mt-8 rounded-2xl bg-red-50 p-6 text-red-800"><p className="font-bold">Dashboard unavailable</p><p className="mt-1">{error}</p><button onClick={() => { setLoading(true); load(); }} className="mt-4 rounded-lg border border-red-300 px-4 py-2 font-semibold">Try again</button></div> : <><div className="mt-8 grid gap-4 sm:grid-cols-2 xl:grid-cols-4">{[["Services", services], ["Pending requests", pending], ["Accepted events", accepted], ["Completed events", completed]].map(([label,value])=><div key={String(label)} className="rounded-2xl border border-[#f0ded8] bg-white p-5 shadow-sm"><p className="text-sm text-slate-600">{label}</p><p className="mt-2 text-3xl font-bold text-[#6b1839]">{value}</p></div>)}</div><section className="mt-8 rounded-2xl border border-[#f0ded8] bg-white p-6 shadow-sm"><div className="flex flex-wrap items-center justify-between gap-3"><div><h2 className="text-xl font-bold text-[#6b1839]">Profile visibility</h2><p className="mt-1 text-sm text-slate-600">{approval === "approved" ? "Your profile is approved and visible to customers." : approval ? "Your profile is pending admin approval." : "Complete your profile before adding services."}</p></div><Link href="/vendor/dashboard/profile" className="rounded-lg border border-[#8B000F] px-4 py-2 text-sm font-semibold text-[#8B000F]">Manage profile</Link></div></section><section className="mt-8 grid gap-5 lg:grid-cols-2"><div className="rounded-2xl border border-[#f0ded8] bg-white p-6 shadow-sm"><h2 className="text-xl font-bold text-[#6b1839]">Recent booking requests</h2><div className="mt-4 space-y-3">{bookings.slice(0,5).map((b)=><div key={b.id} className="rounded-xl bg-[#fff7f3] p-3 text-sm"><p className="font-semibold">{b.customer?.name || "Customer"} · {b.service.name}</p><p className="mt-1 text-slate-600">{b.eventDate} · {b.status === "confirmed" ? "Accepted" : b.status}</p></div>)}{!bookings.length && <p className="rounded-xl border border-dashed border-[#d9bcb1] p-4 text-sm text-slate-600">No booking requests yet.</p>}</div><Link href="/vendor/dashboard/bookings" className="mt-5 inline-block text-sm font-semibold text-[#8B000F] underline">Review bookings</Link></div><div className="rounded-2xl border border-[#f0ded8] bg-white p-6 shadow-sm"><h2 className="text-xl font-bold text-[#6b1839]">Quick actions</h2><div className="mt-4 grid gap-3">{[["Add a service", "/vendor/dashboard/services"], ["Block unavailable dates", "/vendor/dashboard/availability"], ["Review booking requests", "/vendor/dashboard/bookings"]].map(([label,href])=><Link key={href} href={href} className="rounded-xl bg-[#fff7f3] px-4 py-3 font-semibold text-[#8B000F] hover:bg-[#fff0f3]">{label} →</Link>)}</div></div></section></>}</main></div>;
}
